<script setup lang="ts">
import { onMounted,ref } from 'vue'
import { api } from '@/api/client'
import type { User } from '@/types/auth'
const users=ref<User[]>([]);const error=ref<string|null>(null);const busy=ref(false);const load=async()=>{try{users.value=(await api.admin.users()).users}catch(e){error.value=e instanceof Error?e.message:'加载失败'}};const action=async(user:User,name:'disable'|'enable'|'restore'|'revoke-sessions'|'delete')=>{if(name==='delete'&&!confirm(`确认软删除 ${user.characterName}？`))return;busy.value=true;try{if(name==='delete')await api.admin.remove(user.id);else await api.admin.action(user.id,name);await load()}catch(e){error.value=e instanceof Error?e.message:'操作失败'}finally{busy.value=false}};onMounted(load)
</script>
<template><div class="simple-page"><p class="eyebrow">ADMIN</p><h1>用户管理</h1><div v-if="error" class="notice danger">{{ error }}</div><section class="user-list"><article v-for="user in users" :key="user.id" class="prose-card user-card"><div><strong>{{ user.characterName }}</strong><p>{{ user.steamId }} · {{ user.role }} · {{ user.status }}</p><small>注册 {{ new Date(user.createdAt).toLocaleString() }}<br>最后登录 {{ new Date(user.lastLoginAt).toLocaleString() }}<br>最后在线 {{ user.lastSeenAt?new Date(user.lastSeenAt).toLocaleString():'—' }}</small></div><div class="user-actions"><button v-if="user.status==='active'" :disabled="busy" @click="action(user,'disable')">禁用</button><button v-if="user.status==='disabled'" :disabled="busy" @click="action(user,'enable')">恢复</button><button v-if="user.status==='deleted'" :disabled="busy" @click="action(user,'restore')">恢复删除</button><button v-if="user.status!=='deleted'" :disabled="busy" @click="action(user,'delete')">软删除</button><button :disabled="busy" @click="action(user,'revoke-sessions')">撤销会话</button></div></article></section></div></template>
